#!/usr/bin/env python3\n\"\"\"\nRepository Abstraction Layer Generator for API Data Sources\n\nThis script generates a repository abstraction layer that decouples data sources\n(Room database, API clients) from business logic use cases, implementing the\nRepository pattern for the Chimera SDK.\n\nThe generated code provides:\n- Base repository interface for abstraction\n- API data source implementation\n- Local database (Room) implementation\n- Coordinating repository with caching strategies\n- Domain models and example use cases\n\nUsage:\n    python repository_abstraction_layer.py --output-dir <path>\n    python repository_abstraction_layer.py --help\n\"\"\"\n\nfrom __future__ import annotations\n\nimport argparse\nimport os\nfrom pathlib import Path\n\n\ndef generate_repository_abstraction_layer(output_dir: str = \"src/core_data/repositories\"):\n    \"\"\"\n    Generate the complete repository abstraction layer structure.\n    \n    Args:\n        output_dir: Directory path where repository files will be generated\n    \"\"\"\n    \n    # Ensure output directory exists\n    output_path = Path(output_dir)\n    output_path.mkdir(parents=True, exist_ok=True)\n    \n    # Define all file contents\n    files = {\n        \"base_repository.py\": _get_base_repository(),\n        \"api_npc_repository.py\": _get_api_npc_repository(),\n        \"local_npc_repository.py\": _get_local_npc_repository(),\n        \"coordinating_npc_repository.py\": _get_coordinating_npc_repository(),\n        \"models.py\": _get_models(),\n        \"npc_use_case.py\": _get_npc_use_case(),\n        \"example_usage.py\": _get_example_usage(),\n        \"__init__.py\": _get_init_file(),\n    }\n    \n    # Write all files\n    for filename, content in files.items():\n        file_path = output_path / filename\n        with open(file_path, \"w\") as f:\n            f.write(content)\n        print(f\"Created: {file_path}\")\n    \n    # Create README\n    readme_path = output_path / \"README.md\"\n    with open(readme_path, \"w\") as f:\n        f.write(_get_readme_content())\n    print(f\"Created: {readme_path}\")\n    \n    print(f\"\\nRepository abstraction layer successfully generated in: {output_dir}\")\n\n\ndef _get_base_repository():\n    \"\"\"Generate the base repository interface.\"\"\"\n    return '''\"\"\"\nBase Repository Interface\n=========================\n\nAbstract base class defining the contract for all repository implementations.\nThis interface decouples business logic from data source implementation details.\n\"\"\"\n\nfrom abc import ABC, abstractmethod\nfrom typing import Generic, List, Optional, TypeVar\n\nT = TypeVar(\"T\")\n\n\nclass BaseRepository(Generic[T], ABC):\n    \"\"\"\n    Abstract base repository class defining the contract for all repositories.\n    \n    This interface decouples business logic from data source implementation,\n    allowing for:\n    - Multiple data source strategies (API, local database, in-memory)\n    - Caching implementations\n    - Easy testing with mock repositories\n    - Data source switching without affecting use cases\n    \n    Type Parameters:\n        T: The domain model type this repository handles\n    \n    Usage:\n        class NpcRepository(BaseRepository[Npc]):\n            def __init__(self, api_source, local_source):\n                self.api_source = api_source\n                self.local_source = local_source\n            \n            async def get_all(self) -> List[Npc]:\n                # Check cache first\n                cached = await self.local_source.get_all()\n                if cached and not self._is_stale(cached):\n                    return cached\n                \n                # Fetch from API if cache is stale or empty\n                fresh_data = await self.api_source.fetch_all()\n                await self.local_source.save_all(fresh_data)\n                return fresh_data\n    \"\"\"\n\n    @abstractmethod\n    async def get_all(self) -> List[T]:\n        \"\"\"\n        Retrieve all entities of type T.\n        \n        Returns:\n            List of all entities, may be cached or fresh from API\n        \"\"\"\n        pass\n\n    @abstractmethod\n    async def get_by_id(self, entity_id: str) -> Optional[T]:\n        \"\"\"\n        Retrieve a specific entity by its identifier.\n        \n        Args:\n            entity_id: Unique identifier for the entity\n            \n        Returns:\n            The entity if found, None otherwise\n        \"\"\"\n        pass\n\n    @abstractmethod\n    async def save(self, item: T) -> T:\n        \"\"\"\n        Save or update an entity.\n        \n        Args:\n            item: The entity to save\n            \n        Returns:\n            The saved entity (may include generated IDs, timestamps, etc.)\n        \"\"\"\n        pass\n\n    @abstractmethod\n    async def delete(self, entity_id: str) -> bool:\n        \"\"\"\n        Delete an entity by its identifier.\n        \n        Args:\n            entity_id: Unique identifier for the entity to delete\n            \n        Returns:\n            True if deletion was successful, False otherwise\n        \"\"\"\n        pass\n\n    def _is_stale(self, data: List[T], max_age_minutes: int = 30) -> bool:\n        \"\"\"\n        Check if cached data is stale.\n        \n        Args:\n            data: Cached data (should have timestamp field)\n            max_age_minutes: Maximum age in minutes before data is considered stale\n            \n        Returns:\n            True if data is stale, False otherwise\n        \"\"\"\n        # This is a helper method that can be overridden by subclasses\n        # Real implementation would check timestamps on the data\n        return False\n'''\n\n\ndef _get_api_npc_repository():\n    \"\"\"Generate the API NPC repository implementation.\"\"\"\n    return '''\"\"\"\nAPI NPC Repository\n==================\n\nAPI-based repository implementation for NPC entities.\n\nThis repository handles all communication with remote API endpoints,\nproviding a clean abstraction for API data operations.\n\"\"\"\n\nimport aiohttp\nfrom typing import List, Optional\nfrom dataclasses import dataclass, asdict\nimport json\nimport logging\n\nfrom .base_repository import BaseRepository\nfrom ..models import Npc\nfrom ..exceptions import RepositoryError\n\nlogger = logging.getLogger(__name__)\n\n\nclass NpcRepository(BaseRepository[Npc]):\n    \"\"\"\n    API-based repository implementation for Npc entities.\n    \n    This repository handles all communication with remote API endpoints,\n    providing a clean abstraction for API data operations.\n    \n    Features:\n    - Async HTTP requests with aiohttp\n    - Automatic error handling and retry logic\n    - Response validation and transformation\n    - Integration with repository caching layer\n    \n    Args:\n        base_url: Base URL of the API endpoint\n        api_key: Optional API key for authentication\n        timeout: Request timeout in seconds (default: 30)\n    \n    Example:\n        >>> repository = NpcRepository(\n        ...     base_url=\"https://api.chimerasdk.com\",\n        ...     api_key=\"your-api-key\"\n        ... )\n        >>> npcs = await repository.get_all()\n    \"\"\"\n\n    def __init__(\n        self,\n        base_url: str,\n        api_key: Optional[str] = None,\n        timeout: int = 30\n    ):\n        self.base_url = base_url.rstrip(\"/\")\n        self.api_key = api_key\n        self.timeout = aiohttp.ClientTimeout(total=timeout)\n        self._session: Optional[aiohttp.ClientSession] = None\n\n    async def _get_session(self) -> aiohttp.ClientSession:\n        \"\"\"Get or create aiohttp session.\"\"\"\n        if self._session is None or self._session.closed:\n            self._session = aiohttp.ClientSession(timeout=self.timeout)\n        return self._session\n\n    async def _request(\n        self,\n        method: str,\n        endpoint: str,\n        data: Optional[dict] = None\n    ) -> dict:\n        \"\"\"\n        Make an authenticated API request.\n        \n        Args:\n            method: HTTP method (GET, POST, PUT, DELETE)\n            endpoint: API endpoint path\n            data: Optional request body data\n            \n        Returns:\n            JSON response as dictionary\n            \n        Raises:\n            RepositoryError: If request fails or returns error status\n        \"\"\"\n        url = f\"{self.base_url}/{endpoint.lstrip(\"/\")}\"\n        session = await self._get_session()\n        \n        headers = {\"Content-Type\": \"application/json\"}\n        if self.api_key:\n            headers[\"Authorization\"] = f\"Bearer {self.api_key}\"\n        \n        try:\n            async with session.request(\n                method,\n                url,\n                json=data,\n                headers=headers\n            ) as response:\n                if response.status >= 400:\n                    error_text = await response.text()\n                    raise RepositoryError(\n                        f\"API request failed: {response.status} - {error_text}\"\n                    )\n                \n                if response.status == 204:  # No content\n                    return {}\n                \n                return await response.json()\n                \n        except aiohttp.ClientError as e:\n            logger.error(f\"API request error: {e}\")\n            raise RepositoryError(f\"Network error: {e}\")\n\n    async def get_all(self) -> List[Npc]:\n        \"\"\"Fetch all NPC entities from API.\"\"\"\n        try:\n            response = await self._request(\"GET\", \"api/npcs\")\n            items = response.get(\"npcs\", [])\n            return [Npc.from_dict(item) for item in items]\n        except Exception as e:\n            logger.error(f\"Failed to fetch npcs: {e}\")\n            raise\n\n    async def get_by_id(self, entity_id: str) -> Optional[Npc]:\n        \"\"\"Fetch a specific NPC entity by ID.\"\"\"\n        try:\n            response = await self._request(\"GET\", f\"api/npcs/{entity_id}\")\n            return Npc.from_dict(response)\n        except RepositoryError as e:\n            if \"404\" in str(e):\n                return None\n            raise\n\n    async def save(self, item: Npc) -> Npc:\n        \"\"\"Save or update a NPC entity via API.\"\"\"\n        try:\n            data = asdict(item)\n            response = await self._request(\n                \"POST\" if not item.id else \"PUT\",\n                f\"api/npcs/{item.id if item.id else ''}\",\n                data=data\n            )\n            return Npc.from_dict(response)\n        except Exception as e:\n            logger.error(f\"Failed to save npc: {e}\")\n            raise\n\n    async def delete(self, entity_id: str) -> bool:\n        \"\"\"Delete a NPC entity by ID.\"\"\"\n        try:\n            await self._request(\"DELETE\", f\"api/npcs/{entity_id}\")\n            return True\n        except RepositoryError as e:\n            if \"404\" in str(e):\n                return False\n            raise\n\n    async def close(self):\n        \"\"\"Close the aiohttp session.\"\"\"\n        if self._session and not self._session.closed:\n            await self._session.close()\n'''\n\n\ndef _get_local_npc_repository():\n    \"\"\"Generate the local NPC repository implementation.\"\"\"\n    return '''\"\"\"\nLocal NPC Repository\n====================\n\nLocal database repository implementation for NPC entities using Room database.\n\nThis repository handles persistence using local database, providing\nfast local data access and offline support.\n\"\"\"\n\nimport logging\nfrom typing import List, Optional\nfrom dataclasses import dataclass, asdict\nimport time\n\nfrom .base_repository import BaseRepository\nfrom ..models import Npc\nfrom ..database import RoomDatabase\nfrom ..exceptions import RepositoryError\n\nlogger = logging.getLogger(__name__)\n\n\nclass LocalNpcRepository(BaseRepository[Npc]):\n    \"\"\"\n    Local database repository implementation for Npc entities.\n    \n    This repository handles persistence using Room database, providing\n    fast local data access and offline support.\n    \n    Features:\n    - Room database integration\n    - Efficient local queries\n    - Automatic schema migrations\n    - Batch operations for performance\n    \n    Args:\n        database: Room database instance\n    \n    Example:\n        >>> db = RoomDatabase.get_instance(context)\n        >>> repository = LocalNpcRepository(db)\n        >>> npcs = await repository.get_all()\n    \"\"\"\n\n    def __init__(self, database: RoomDatabase):\n        self.database = database\n        self._cache: Optional[List[Npc]] = None\n        self._cache_timestamp: Optional[float] = None\n\n    async def get_all(self) -> List[Npc]:\n        \"\"\"Retrieve all NPC entities from local database.\"\"\"\n        try:\n            # Check cache first\n            if self._cache and self._cache_timestamp:\n                if time.time() - self._cache_timestamp < 300:  # 5 minutes cache\n                    return self._cache\n            \n            entities = await self.database.query_all_npcs()\n            self._cache = entities\n            self._cache_timestamp = time.time()\n            return entities\n            \n        except Exception as e:\n            logger.error(f\"Failed to fetch local npcs: {e}\")\n            raise RepositoryError(f\"Local query failed: {e}\")\n\n    async def get_by_id(self, entity_id: str) -> Optional[Npc]:\n        \"\"\"Fetch a specific NPC entity by ID from local database.\"\"\"\n        try:\n            return await self.database.query_npc_by_id(entity_id)\n        except Exception as e:\n            logger.error(f\"Failed to fetch local npc {{entity_id}}: {e}\")\n            raise RepositoryError(f\"Local query failed: {e}\")\n\n    async def save(self, item: Npc) -> Npc:\n        \"\"\"Save or update a NPC entity in local database.\"\"\"\n        try:\n            # Invalidate cache on write\n            self._cache = None\n            self._cache_timestamp = None\n            \n            if item.id:\n                await self.database.update_npc(item)\n            else:\n                item.id = await self.database.insert_npc(item)\n            \n            # Update cache\n            if self._cache is not None:\n                self._cache.append(item)\n            \n            return item\n            \n        except Exception as e:\n            logger.error(f\"Failed to save local npc: {e}\")\n            raise RepositoryError(f\"Local save failed: {e}\")\n\n    async def delete(self, entity_id: str) -> bool:\n        \"\"\"Delete a NPC entity from local database.\"\"\"\n        try:\n            # Invalidate cache on write\n            self._cache = None\n            self._cache_timestamp = None\n            \n            result = await self.database.delete_npc(entity_id)\n            return result > 0\n            \n        except Exception as e:\n            logger.error(f\"Failed to delete local npc {{entity_id}}: {e}\")\n            raise RepositoryError(f\"Local delete failed: {e}\")\n\n    async def clear_cache(self):\n        \"\"\"Clear the local cache.\"\"\"\n        self._cache = None\n        self._cache_timestamp = None\n\n    async def save_batch(self, items: List[Npc]) -> List[Npc]:\n        \"\"\"\n        Save multiple entities in a batch transaction.\n        \n        Args:\n            items: List of entities to save\n            \n        Returns:\n            List of saved entities\n        \"\"\"\n        try:\n            async with self.database.transaction():\n                saved = []\n                for item in items:\n                    saved.append(await self.save(item))\n            \n            # Invalidate cache after batch operation\n            self._cache = None\n            self._cache_timestamp = None\n            \n            return saved\n            \n        except Exception as e:\n            logger.error(f\"Failed batch save for npcs: {e}\")\n            raise RepositoryError(f\"Batch save failed: {e}\")\n'''\n\n\ndef _get_coordinating_npc_repository():\n    \"\"\"Generate the coordinating NPC repository implementation.\"\"\"\n    return '''\"\"\"\nCoordinating NPC Repository\n===========================\n\nCoordinating repository that manages both API and local data sources for NPC entities.\n\nThis repository implements sophisticated caching strategies and data source coordination:\n\nCaching Strategy:\n- Check local cache first (fast, offline-capable)\n- If cache is stale or empty, fetch from API\n- Update local cache with fresh data\n- Background refresh for stale data\n\nData Source Coordination:\n- Automatic fallback to local data when API is unavailable\n- Conflict resolution strategies\n- Synchronization management\n\nArgs:\n    api_source: API-based data source\n    local_source: Local database data source\n    refresh_threshold: Cache freshness threshold in minutes (default: 30)\n\nExample:\n    >>> api_repo = NpcRepository(\n    ...     base_url=\"https://api.chimerasdk.com\",\n    ...     api_key=\"your-api-key\"\n    ... )\n    >>> local_repo = LocalNpcRepository(database)\n    >>> repository = CoordinatingNpcRepository(api_repo, local_repo)\n    >>> \n    >>> # Get data with automatic caching\n    >>> npcs = await repository.get_all()\n    >>> \n    >>> # Save will update both sources\n    >>> new_npc = Npc(name=\"New NPC\")\n    >>> saved = await repository.save(new_npc)\n\"\"\"\n\nimport logging\nfrom typing import List, Optional\nfrom dataclasses import dataclass\n\nfrom .api_npc_repository import NpcRepository as ApiNpcRepository\nfrom .local_npc_repository import LocalNpcRepository\nfrom ..models import Npc\n\nlogger = logging.getLogger(__name__)\n\n\nclass CoordinatingNpcRepository(BaseRepository[Npc]):\n    \"\"\"\n    Coordinating repository that manages both API and local data sources.\n    \n    This repository implements sophisticated caching strategies and\n    data source coordination:\n    \n    Caching Strategy:\n    - Check local cache first (fast, offline-capable)\n    - If cache is stale or empty, fetch from API\n    - Update local cache with fresh data\n    - Background refresh for stale data\n    \n    Data Source Coordination:\n    - Automatic fallback to local data when API is unavailable\n    - Conflict resolution strategies\n    - Synchronization management\n    \n    Args:\n        api_source: API-based data source\n        local_source: Local database data source\n        refresh_threshold: Cache freshness threshold in minutes (default: 30)\n    \n    Example:\n        >>> api_repo = NpcRepository(\n        ...     base_url=\"https://api.chimerasdk.com\",\n        ...     api_key=\"your-api-key\"\n        ... )\n        >>> local_repo = LocalNpcRepository(database)\n        >>> repository = CoordinatingNpcRepository(api_repo, local_repo)\n        >>> \n        >>> # Get data with automatic caching\n        >>> npcs = await repository.get_all()\n        >>> \n        >>> # Save will update both sources\n        >>> new_npc = Npc(name=\"New NPC\")\n        >>> saved = await repository.save(new_npc)\n    \"\"\"\n\n    def __init__(\n        self,\n        api_source: ApiNpcRepository,\n        local_source: LocalNpcRepository,\n        refresh_threshold: int = 30\n    ):\n        self.api_source = api_source\n        self.local_source = local_source\n        self.refresh_threshold = refresh_threshold\n\n    async def get_all(self) -> List[Npc]:\n        \"\"\"\n        Retrieve all NPC entities with smart caching.\n        \n        Implementation:\n        1. Try to get data from local source (fast)\n        2. Check if data is fresh (within refresh_threshold minutes)\n        3. If stale or unavailable, fetch from API\n        4. Update local cache with fresh data\n        5. Return data to caller\n        \n        Returns:\n            List of NPC entities\n        \"\"\"\n        try:\n            # Step 1: Check local cache\n            local_data = await self.local_source.get_all()\n            \n            if local_data and not self._is_cache_stale(local_data):\n                logger.debug(\"Returning cached npcs\")\n                return local_data\n            \n            # Step 2: Cache is stale or empty, fetch from API\n            logger.debug(\"Cache is stale or empty, fetching from API\")\n            api_data = await self.api_source.get_all()\n            \n            # Step 3: Update local cache\n            if api_data:\n                await self.local_source.save_batch(api_data)\n            \n            return api_data\n            \n        except Exception as e:\n            logger.warning(f\"API fetch failed, falling back to local data: {e}\")\n            # Fallback to local data even if stale\n            local_data = await self.local_source.get_all()\n            if local_data:\n                return local_data\n            raise\n\n    async def get_by_id(self, entity_id: str) -> Optional[Npc]:\n        \"\"\"\n        Retrieve a specific NPC entity.\n        \n        Strategy:\n        1. Try local source first\n        2. If not found locally, try API\n        3. If found in API, cache locally\n        \n        Args:\n            entity_id: Unique identifier\n            \n        Returns:\n            Entity if found, None otherwise\n        \"\"\"\n        try:\n            # Try local source first\n            local_entity = await self.local_source.get_by_id(entity_id)\n            if local_entity:\n                return local_entity\n            \n            # Fall back to API\n            api_entity = await self.api_source.get_by_id(entity_id)\n            if api_entity:\n                await self.local_source.save(api_entity)\n            \n            return api_entity\n            \n        except Exception as e:\n            logger.warning(f\"Failed to get npc {{entity_id}}: {e}\")\n            # Try local source as last resort\n            try:\n                return await self.local_source.get_by_id(entity_id)\n            except:\n                raise\n\n    async def save(self, item: Npc) -> Npc:\n        \"\"\"\n        Save entity to both API and local sources.\n        \n        Implements write-through caching strategy:\n        1. Save to API first (source of truth)\n        2. Update local cache\n        3. Return saved entity\n        \n        Args:\n            item: Entity to save\n            \n        Returns:\n            Saved entity with generated IDs/timestamps\n        \"\"\"\n        try:\n            # Step 1: Save to API (source of truth)\n            saved_item = await self.api_source.save(item)\n            \n            # Step 2: Update local cache\n            await self.local_source.save(saved_item)\n            \n            return saved_item\n            \n        except Exception as e:\n            logger.error(f\"Failed to save npc: {e}\")\n            raise\n\n    async def delete(self, entity_id: str) -> bool:\n        \"\"\"\n        Delete entity from both sources.\n        \n        Args:\n            entity_id: Unique identifier to delete\n            \n        Returns:\n            True if successfully deleted from both sources\n        \"\"\"\n        try:\n            # Delete from both sources\n            api_result = await self.api_source.delete(entity_id)\n            local_result = await self.local_source.delete(entity_id)\n            \n            return api_result and local_result\n            \n        except Exception as e:\n            logger.error(f\"Failed to delete npc {{entity_id}}: {e}\")\n            raise\n\n    def _is_cache_stale(self, data: List[Npc]) -> bool:\n        \"\"\"\n        Check if cached data is stale based on refresh threshold.\n        \n        Args:\n            data: Cached data (should have updated_at timestamp)\n            \n        Returns:\n            True if cache should be refreshed\n        \"\"\"\n        # In a real implementation, this would check timestamps\n        # For this template, we use a simple time-based check\n        import time\n        \n        if not data or not hasattr(data[0], 'updated_at'):\n            return True\n        \n        # Check if oldest entry is stale\n        oldest_timestamp = min(\n            getattr(item, 'updated_at', 0) \n            for item in data\n        )\n        \n        age_minutes = (time.time() - oldest_timestamp) / 60\n        return age_minutes > self.refresh_threshold\n\n    async def sync(self) -> dict:\n        \"\"\"\n        Synchronize local and remote data sources.\n        \n        Returns:\n            Dictionary with sync statistics\n        \"\"\"\n        try:\n            # Fetch fresh data from API\n            api_data = await self.api_source.get_all()\n            \n            # Replace local data\n            if api_data:\n                await self.local_source.save_batch(api_data)\n            \n            return {\n                \"status\": \"success\",\n                \"synced_count\": len(api_data),\n                \"timestamp\": datetime.datetime.now().isoformat()\n            }\n            \n        except Exception as e:\n            logger.error(f\"Sync failed: {e}\")\n            return {\n                \"status\": \"failed\",\n                \"error\": str(e),\n                \"timestamp\": datetime.datetime.now().isoformat()\n            }\n'''\n\n\ndef _get_models():\n    \"\"\"Generate the domain model.\"\"\"\n    return '''\"\"\"\nDomain Models\n=============\n\nCore business entities independent of data storage concerns.\n\"\"\"\n\nfrom dataclasses import dataclass, field\nfrom typing import Optional\nimport time\n\n\n@dataclass\nclass Npc:\n    \"\"\"\n    Domain model for NPC (Non-Player Character).\n    \n    This represents the core business entity in the application,\n    independent of any data storage concerns.\n    \n    Attributes:\n        id: Unique identifier (optional for new entities)\n        name: Name of the NPC\n        character_type: Type/category of the NPC\n        level: Experience level\n        created_at: Timestamp when entity was created\n        updated_at: Timestamp when entity was last updated\n    \"\"\"\n    \n    id: Optional[str] = None\n    name: str = \"\"\n    character_type: str = \"\"\n    level: int = 1\n    created_at: float = field(default_factory=time.time)\n    updated_at: float = field(default_factory=time.time)\n    \n    def to_dict(self) -> dict:\n        \"\"\"Convert model to dictionary for serialization.\"\"\"\n        return {\n            \"id\": self.id,\n            \"name\": self.name,\n            \"character_type\": self.character_type,\n            \"level\": self.level,\n            \"created_at\": self.created_at,\n            \"updated_at\": self.updated_at\n        }\n    \n    @classmethod\n    def from_dict(cls, data: dict) -> Npc:\n        \"\"\"\n        Create model instance from dictionary.\n        \n        Args:\n            data: Dictionary containing model data\n            \n        Returns:\n            New Npc instance\n        \"\"\"\n        # Handle both old and new format\n        if \"created_at\" in data and \"updated_at\" in data:\n            instance = cls(\n                id=data.get(\"id\"),\n                name=data.get(\"name\", \"\"),\n                character_type=data.get(\"character_type\", \"\"),\n                level=data.get(\"level\", 1),\n                created_at=data[\"created_at\"],\n                updated_at=data[\"updated_at\"]\n            )\n        else:\n            instance = cls(\n                id=data.get(\"id\"),\n                name=data.get(\"name\", \"\"),\n                character_type=data.get(\"character_type\", \"\"),\n                level=data.get(\"level\", 1)\n            )\n        \n        # Set any additional fields\n        for key, value in data.items():\n            if not hasattr(instance, key):\n                setattr(instance, key, value)\n        \n        # Update timestamp if not set\n        if not instance.updated_at:\n            instance.updated_at = time.time()\n        \n        return instance\n'''\n\n\ndef _get_npc_use_case():\n    \"\"\"Generate the NPC use case example.\"\"\"\n    return '''\"\"\"\nNPC Use Case Example\n====================\n\nExample use case demonstrating repository usage for NPC management.\n\nThis use case shows how business logic interacts with the repository\nabstraction without knowing the underlying data source implementation.\n\"\"\"\n\nimport asyncio\nimport logging\nimport time\nfrom typing import List, Optional\n\nfrom .models import Npc\n\nlogger = logging.getLogger(__name__)\n\n\nclass NpcUseCase:\n    \"\"\"\n    Example use case demonstrating repository usage.\n    \n    This use case shows how business logic interacts with the repository\n    abstraction without knowing the underlying data source implementation.\n    \n    Args:\n        repository: Repository instance (can be API, local, or coordinating)\n    \n    Example:\n        >>> # Using coordinating repository with caching\n        >>> repo = CoordinatingNpcRepository(api_source, local_source)\n        >>> use_case = NpcUseCase(repo)\n        >>> npcs = await use_case.get_all_active_npcs()\n    \"\"\"\n\n    def __init__(self, repository: \"CoordinatingNpcRepository\"):\n        self.repository = repository\n\n    async def get_all(self) -> List[Npc]:\n        \"\"\"\n        Get all NPC entities.\n        \n        Returns:\n            List of all NPC entities\n        \"\"\"\n        return await self.repository.get_all()\n\n    async def get_by_id(self, entity_id: str) -> Optional[Npc]:\n        \"\"\"\n        Get a specific NPC entity by ID.\n        \n        Args:\n            entity_id: Unique identifier\n            \n        Returns:\n            Entity if found, None otherwise\n        \"\"\"\n        return await self.repository.get_by_id(entity_id)\n\n    async def create(self, **kwargs) -> Npc:\n        \"\"\"\n        Create a new NPC entity.\n        \n        Args:\n            **kwargs: NPC attributes (name, character_type, level, etc.)\n            \n        Returns:\n            Created NPC entity\n        \"\"\"\n        entity = Npc(**kwargs)\n        return await self.repository.save(entity)\n\n    async def update(self, entity_id: str, **kwargs) -> Optional[Npc]:\n        \"\"\"\n        Update an existing NPC entity.\n        \n        Args:\n            entity_id: Entity ID to update\n            **kwargs: Attributes to update\n            \n        Returns:\n            Updated entity if successful, None otherwise\n        \"\"\"\n        existing = await self.repository.get_by_id(entity_id)\n        if not existing:\n            return None\n        \n        # Update attributes\n        for key, value in kwargs.items():\n            if hasattr(existing, key):\n                setattr(existing, key, value)\n        \n        existing.updated_at = time.time()\n        return await self.repository.save(existing)\n\n    async def delete(self, entity_id: str) -> bool:\n        \"\"\"\n        Delete an NPC entity.\n        \n        Args:\n            entity_id: Entity ID to delete\n            \n        Returns:\n            True if deleted successfully\n        \"\"\"\n        return await self.repository.delete(entity_id)\n\n    async def list_all(self) -> List[Npc]:\n        \"\"\"\n        List all entities with error handling.\n        \n        Returns:\n            List of entities or empty list on failure\n        \"\"\"\n        try:\n            return await self.repository.get_all()\n        except Exception as e:\n            logger.error(f\"Failed to list npcs: {e}\")\n            return []\n\n    async def get_npcs_by_level(self, min_level: int, max_level: int) -> List[Npc]:\n        \"\"\"\n        Get NPCs within a specific level range.\n        \n        Args:\n            min_level: Minimum level (inclusive)\n            max_level: Maximum level (inclusive)\n            \n        Returns:\n            List of NPCs within the level range\n        \"\"\"\n        all_npcs = await self.repository.get_all()\n        return [npc for npc in all_npcs \n                if min_level <= npc.level <= max_level]\n'''\n\n\ndef _get_example_usage():\n    \"\"\"Generate the async example usage file.\"\"\"\n    return '''\"\"\"\nAsync Example Usage\n===================\n\nThis demonstrates the repository abstraction layer in action with async operations.\n\"\"\"\n\nimport asyncio\nimport logging\n\n# Configure logging\nlogging.basicConfig(level=logging.INFO)\n\n\nasync def main():\n    \"\"\"\n    Example usage of the repository abstraction layer.\n    \n    This demonstrates:\n    1. Creating repositories with different data sources\n    2. Using coordinating repository for smart caching\n    3. Implementing use cases that work with the abstraction\n    \"\"\"\n    \n    # Example 1: Using coordinating repository (recommended)\n    print(\"Example 1: Coordinating Repository with Caching\")\n    print(\"=\" * 50)\n    \n    # Initialize data sources\n    # api_source = NpcRepository(\n    #     base_url=\"https://api.chimerasdk.com\",\n    #     api_key=\"your-api-key\"\n    # )\n    # local_source = LocalNpcRepository(database)\n    # \n    # # Create coordinating repository\n    # repository = CoordinatingNpcRepository(api_source, local_source)\n    \n    # Example 2: Using API repository directly\n    print(\"Example 2: Direct API Repository\")\n    print(\"=\" * 50)\n    \n    # api_repo = NpcRepository(\n    #     base_url=\"https://api.chimerasdk.com\",\n    #     api_key=\"demo-key\"\n    # )\n    # \n    # # Fetch all entities\n    # entities = await api_repo.get_all()\n    # print(f\"Fetched {len(entities)} entities\")\n    \n    # Example 3: Using local repository directly\n    print(\"Example 3: Direct Local Repository\")\n    print(\"=\" * 50)\n    \n    # local_repo = LocalNpcRepository(database)\n    # \n    # # Save an entity\n    # new_entity = Npc(name=\"Test Entity\")\n    # saved = await local_repo.save(new_entity)\n    # print(f\"Saved entity with ID: {saved.id}\")\n    \n    print(\"\\\\nRepository abstraction layer ready for use!\")\n\n\nif __name__ == \"__main__\":\n    asyncio.run(main())\n'''\n\n\ndef _get_init_file():\n    \"\"\"Generate the __init__.py file.\"\"\"\n    return '''\n# Repository Abstraction Layer\n\nfrom .base_repository import BaseRepository\nfrom .api_npc_repository import NpcRepository\nfrom .local_npc_repository import LocalNpcRepository\nfrom .coordinating_npc_repository import CoordinatingNpcRepository\nfrom .models import Npc\n\n__all__ = [\n    \"BaseRepository\",\n    \"NpcRepository\",\n    \"LocalNpcRepository\",\n    \"CoordinatingNpcRepository\",\n    \"Npc\",\n]\n'''\n\n\ndef _get_readme_content():\n    \"\"\"Generate README content.\"\"\"\n    return '''# Repository Abstraction Layer\n\nThis directory contains the repository abstraction layer for the Chimera SDK,\nimplementing the Repository pattern to decouple data sources from business logic.\n\n## Architecture\n\n